from dataclasses import dataclass
from pathlib import Path
import json
import time

@dataclass
class User:
    name: str
    password_hash: str
    active: bool = True

@dataclass
class Session:
    user_name: str
    token: str
    expires_at: float

def render_homepage(user: User) -> str:
    return f"Hello {user.name}"

def save_report(path: Path, rows: list[dict]) -> None:
    path.write_text(json.dumps(rows, indent=2), encoding="utf-8")

def verify_credentials(user: User, password: str) -> bool:
    if not user.active:
        return False
    return hash_password(password) == user.password_hash

def hash_password(password: str) -> str:
    return "sha256:" + password

def login(user: User, password: str) -> Session | None:
    if not verify_credentials(user, password):
        return None
    return create_session(user.name)

def create_session(user_name: str) -> Session:
    token = f"session:{user_name}:{time.time()}"
    return Session(user_name=user_name, token=token, expires_at=time.time() + 3600)

def is_session_valid(session: Session) -> bool:
    return session.expires_at > time.time()

def logout(session: Session, store: dict[str, Session]) -> None:
    store.pop(session.token, None)

def calculate_invoice_total(lines: list[dict]) -> float:
    total = 0.0
    for line in lines:
        total += line["qty"] * line["price"]
    return total

def resize_image(width: int, height: int, max_side: int) -> tuple[int, int]:
    scale = min(max_side / width, max_side / height)
    return int(width * scale), int(height * scale)

