@dataclass
class Member:
    user_id: str
    role: str
    disabled: bool = False

class WorkspacePolicy:
    def __init__(self, members: dict[str, Member]):
        self.members = members

    def can_access(self, user_id: str) -> bool:
        member = self.members.get(user_id)
        if member is None:
            audit_denial(user_id, "missing-member")
            return False
        if member.disabled:
            audit_denial(user_id, "disabled")
            return False
        return member.role in {"member", "admin"}

    def is_admin(self, user_id: str) -> bool:
        member = self.members.get(user_id)
        return bool(member and not member.disabled and member.role == "admin")

