import hashlib
import hmac
import json
import time

MAX_SKEW_SECONDS = 300
DEFAULT_THEME = "light"

def parse_timestamp(headers: dict[str, str]) -> int:
    return int(headers.get("x-webhook-timestamp", "0"))

def verify_webhook_signature(body: bytes, headers: dict[str, str], secret: bytes) -> bool:
    timestamp = parse_timestamp(headers)
    if abs(time.time() - timestamp) > MAX_SKEW_SECONDS:
        return False
    supplied = headers.get("x-webhook-signature", "")
    expected = hmac.new(secret, body, hashlib.sha256).hexdigest()
    return hmac.compare_digest(supplied, expected)

def render_status_page(config: dict) -> str:
